Since I am a text-based AI, I cannot directly generate a binary 3D file (like an `.obj` or `.fbx`) or render a video for you. However, I can provide you with the **complete code** to render a 3D house in your browser right now using **Three.js**.

This code creates a procedural house (walls, roof, windows, door) using geometric primitives.

### How to use this:
1.  Create a new file on your computer named `house.html`.
2.  Paste the code below into that file.
3.  Open `house.html` in any modern web browser (Chrome, Firefox, Edge).

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. SCENE SETUP
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        renderer.shadowMap.type = THREE.PCFSoftShadowMap;
        document.body.appendChild(renderer.domElement);

        // 2. CONTROLS
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 2, 0);

        // 3. LIGHTING
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1.2);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. MATERIALS
        const materials = {
            wall: new THREE.MeshStandardMaterial({ color: 0xeeeeee, roughness: 0.8 }),
            roof: new THREE.MeshStandardMaterial({ color: 0x8B4513, roughness: 0.9 }),
            window: new THREE.MeshStandardMaterial({ color: 0x88ccff, roughness: 0.1, metalness: 0.1 }),
            door: new THREE.MeshStandardMaterial({ color: 0x5c3a21, roughness: 0.7 }),
            grass: new THREE.MeshStandardMaterial({ color: 0x4caf50 }),
            wood: new THREE.MeshStandardMaterial({ color: 0x8B4513 })
        };

        // 5. BUILDING THE HOUSE
        const houseGroup = new THREE.Group();

        // --- Ground ---
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const ground = new THREE.Mesh(groundGeo, materials.grass);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // --- Main Body ---
        const bodyGeo = new THREE.BoxGeometry(8, 4, 8);
        const body = new THREE.Mesh(bodyGeo, materials.wall);
        body.position.y = 2;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // --- Roof ---
        const roofGeo = new THREE.ConeGeometry(7, 3, 4);
        const roof = new THREE.Mesh(roofGeo, materials.roof);
        roof.position.y = 5.5;
        roof.rotation.y = Math.PI / 4;
        roof.castShadow = true;
        houseGroup.add(roof);

        // --- Windows ---
        function createWindow(x, z, y, w, h) {
            const winGeo = new THREE.BoxGeometry(w, h, 0.2);
            const win = new THREE.Mesh(winGeo, materials.window);
            win.position.set(x, y, z);
            win.castShadow = true;
            houseGroup.add(win);
        }

        // Front Windows
        createWindow(0, -3.5, 2, 1.5, 1.5);
        createWindow(0, 3.5, 2, 1.5, 1.5);
        // Side Windows
        createWindow(-3.5, 0, 2, 1.5, 1.5);
        createWindow(3.5, 0, 2, 1.5, 1.5);

        // --- Door ---
        const doorGeo = new THREE.BoxGeometry(1.5, 2.5, 0.2);
        const door = new THREE.Mesh(doorGeo, materials.door);
        door.position.set(0, 1.25, 4.1);
        door.castShadow = true;
        houseGroup.add(door);

        // --- Chimney ---
        const chimneyGeo = new THREE.BoxGeometry(1, 2, 1);
        const chimney = new THREE.Mesh(chimneyGeo, materials.wall);
        chimney.position.set(2, 6, 2);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // 6. ANIMATION LOOP
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### What this code does:
1.  **Setup:** Initializes a 3D scene, camera, and renderer using the Three.js library (loaded directly from a CDN, so no installation is required).
2.  **Lighting:** Adds a directional light (sun) to cast realistic shadows and an ambient light to fill in the dark areas.
3.  **Geometry Construction:**
    *   **Body:** A white cube for the main walls.
    *   **Roof:** A cone rotated to look like a pyramid roof.
    *   **Details:** A function `createWindow` is used to programmatically place windows on the front and sides, plus a door and a chimney.
4.  **Interactivity:** Adds `OrbitControls`, allowing you to click and drag to rotate around the house and scroll to zoom in/out.
5.  **Environment:** Adds a green plane for grass and sky blue background with fog for depth.
